const body = $json.body ?? $json;

if (body.tipo !== 'reserva_mesa') {
  throw new Error(`Tipo de solicitud no soportado: ${body.tipo}`);
}

const requiredFields = ['nombre', 'telefono', 'fecha', 'hora', 'personas'];

for (const field of requiredFields) {
  if (body[field] === undefined || body[field] === null || body[field] === '') {
    throw new Error(`Campo obligatorio vacío: ${field}`);
  }
}

const nombre = String(body.nombre).trim();
const telefono = String(body.telefono).trim();
const fecha = String(body.fecha).trim();
const hora = String(body.hora).trim();
const personas = Number(body.personas);

if (!Number.isInteger(personas) || personas <= 0) {
  throw new Error('El número de personas debe ser mayor que 0');
}

const alguienAlergico = Boolean(body.alguien_alergico);
const detalleAlergias = body.detalle_alergias || 'No indicado';

// Para España en mayo es +02:00.
// Si quieres algo 100% dinámico con zona horaria, también se puede hacer con Luxon.
const inicioEvento = `${fecha}T${hora}:00+02:00`;

const [hour, minute] = hora.split(':').map(Number);
const startDate = new Date(`${fecha}T${hora}:00+02:00`);
const endDate = new Date(startDate.getTime() + 90 * 60 * 1000);
const finEvento = endDate.toISOString();

const asuntoEmail = `Nueva reserva de mesa - ${nombre} - ${fecha} ${hora}`;

const cuerpoEmailHtml = `
<div style="font-family: Arial, sans-serif; font-size: 15px; color: #222; line-height: 1.5;">
  <h2 style="margin: 0 0 16px 0; color: #111;">
    Nueva reserva de mesa
  </h2>

  <p style="margin: 0 0 16px 0;">
    Se ha recibido una nueva reserva desde la web de <strong>Sabor y Salsa</strong>.
  </p>

  <table style="border-collapse: collapse; width: 100%; max-width: 600px; margin-bottom: 20px;">
    <tr>
      <td style="padding: 8px 12px; border: 1px solid #ddd; background: #f7f7f7;"><strong>Nombre</strong></td>
      <td style="padding: 8px 12px; border: 1px solid #ddd;">${nombre}</td>
    </tr>
    <tr>
      <td style="padding: 8px 12px; border: 1px solid #ddd; background: #f7f7f7;"><strong>Teléfono</strong></td>
      <td style="padding: 8px 12px; border: 1px solid #ddd;">${telefono}</td>
    </tr>
    <tr>
      <td style="padding: 8px 12px; border: 1px solid #ddd; background: #f7f7f7;"><strong>Fecha</strong></td>
      <td style="padding: 8px 12px; border: 1px solid #ddd;">${fecha}</td>
    </tr>
    <tr>
      <td style="padding: 8px 12px; border: 1px solid #ddd; background: #f7f7f7;"><strong>Hora</strong></td>
      <td style="padding: 8px 12px; border: 1px solid #ddd;">${hora}</td>
    </tr>
    <tr>
      <td style="padding: 8px 12px; border: 1px solid #ddd; background: #f7f7f7;"><strong>Personas</strong></td>
      <td style="padding: 8px 12px; border: 1px solid #ddd;">${personas}</td>
    </tr>
    <tr>
      <td style="padding: 8px 12px; border: 1px solid #ddd; background: #f7f7f7;"><strong>Alergias</strong></td>
      <td style="padding: 8px 12px; border: 1px solid #ddd;">${alguienAlergico ? 'Sí' : 'No'}</td>
    </tr>
    <tr>
      <td style="padding: 8px 12px; border: 1px solid #ddd; background: #f7f7f7;"><strong>Detalle alergias</strong></td>
      <td style="padding: 8px 12px; border: 1px solid #ddd;">${detalleAlergias}</td>
    </tr>
  </table>

  <p style="margin: 0 0 8px 0;">
    <strong>Origen:</strong> ${body.origen || 'No indicado'}
  </p>

  <p style="margin: 0 0 20px 0;">
    <strong>Enviado en:</strong> ${body.enviado_en || 'No indicado'}
  </p>

  <div style="padding: 12px 16px; background: #fff7e6; border: 1px solid #ffd591; border-radius: 6px;">
    <strong>Siguiente paso:</strong><br>
    Confirmar disponibilidad y contactar con el cliente si fuera necesario.
  </div>
</div>
`.trim();

const tituloEvento = `Reserva mesa - ${nombre} - ${personas} pax`;

const descripcionEvento = `
Reserva recibida desde la web.

Nombre: ${nombre}
Teléfono: ${telefono}
Personas: ${personas}

Alergias: ${alguienAlergico ? 'Sí' : 'No'}
Detalle alergias: ${detalleAlergias}

Origen: ${body.origen || 'No indicado'}
Enviado en: ${body.enviado_en || 'No indicado'}
`.trim();

return [
  {
    json: {
      nombre,
      telefono,
      fecha,
      hora,
      personas,
      alguien_alergico: alguienAlergico,
      detalle_alergias: detalleAlergias,
      inicio_evento: inicioEvento,
      fin_evento: finEvento,
      asunto_email: asuntoEmail,
      cuerpo_email_html: cuerpoEmailHtml,
      titulo_evento: tituloEvento,
      descripcion_evento: descripcionEvento,
      email_restaurante: 'barsaborysalsa@gmail.com'
    }
  }
];
